def correct_bracketing(brackets: str):
    """ brackets is a string of "(" and ")".
    return True if every opening bracket has a corresponding closing bracket.

    >>> correct_bracketing("(")
    False
    >>> correct_bracketing("()")
    True
    >>> correct_bracketing("(()())")
    True
    >>> correct_bracketing(")(()")
    False
    """

    # check for empty brackets:
    if len(brackets) == 0:
        raise ValueError("Empty brackets are not accepted")

    stack = []

    for i in brackets:
        # check for opening brackets:
        if i in "(":
            # check for empty brackets:
            if len(stack) == 0:
                return False
            # check for closing brackets:
            elif stack[len(stack)-1] == ")":
                return False
            # check for opening brackets:
            else:
                stack.append(i)
